                key = (tuple(args), frozenset(kwargs.items()))
            else:
                key = (args, frozenset(kwargs.items()))
            if key in cache.cache:
                return cache.get(key)
            result = func(*args, **kwargs)
            cache.put(key, result)
            return result

        return wrapper

    return decorator

