def size_to_bytes(size: str) -> int:

    size = size.strip().upper()
    multipliers = {
        'B': 1,
        'K': 1000,
        'M': 1000000,
        'G': 1000000000,
        'T': 1000000000000,
    }

    if size[-1] in multipliers:
        number = float(size[:-1])
        unit = size[-1]
    else:
        number = float(size)
        unit = 'B'

    return int(number * multipliers[unit])

