    from datetime import datetime, timedelta
    import re
    from dateutil import tz

    # Regex patterns for parsing
    date_pattern = r'(\d{4})(?:-(\d{2})(?:-(\d{2}))?)?'
    week_pattern = r'(\d{4})-W(\d{2})(?:-?(\d{1}))?'
    time_pattern = r'(\d{2})(?::(\d{2})(?::(\d{2})(?:\.(\d+))?)?)?'
    tz_pattern = r'Z|([+-]\d{2}):?(\d{2})?|([+-]\d{2})(\d{2})?|([+-]\d{2})'

    # Combine patterns
    iso_pattern = re.compile(
        rf'^{date_pattern}(?:T{time_pattern})?({tz_pattern})?$'
    )

    match = iso_pattern.match(dt_str)
    if not match:
        raise ValueError(f"Invalid ISO-8601 date string: {dt_str}")

    # Extract date components
    year, month, day = match.group(1), match.group(2), match.group(3)
    if month is None:
        month = 1
    if day is None:
        day = 1

    # Handle week date
    if match.group(4):
        week, week_day = match.group(5), match.group(6)
        if week_day is None:
            week_day = 0
        date = datetime.strptime(f'{year}-W{week}-{week_day}', "%Y-W%W-%w").date()
    else:
        date = datetime(int(year), int(month), int(day))

    # Extract time components
    hour, minute, second, microsecond = match.group(7), match.group(8), match.group(9), match.group(10)
    if hour is None:
        hour = 0
    if minute is None:
        minute = 0
    if second is None:
        second = 0
    if microsecond is None:
        microsecond = 0

    # Create datetime object
    dt = datetime(date.year, date.month, date.day, int(hour), int(minute), int(second), int(microsecond))

    # Handle timezone
    tz_info = match.group(11)
    if tz_info == 'Z':
        dt = dt.replace(tzinfo=tz.tzutc())
    elif tz_info:
        if ':' in tz_info:
            offset = tz.tzoffset(None, int(tz_info[:3]) * 3600 + int(tz_info[4:]) * 60)
        else:
            offset = tz.tzoffset(None, int(tz_info) * 3600)
        dt = dt.replace(tzinfo=offset)

    return dt

